import{_ as t,o as i,c as r,a3 as s}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"Notely AI Knowledge Retrieval Validation Report","description":"","frontmatter":{},"headers":[],"relativePath":"ai/ai_validation.md","filePath":"ai/ai_validation.md","lastUpdated":1784606116000}'),a={name:"ai/ai_validation.md"};function o(n,e,l,d,c,h){return i(),r("div",null,[...e[0]||(e[0]=[s(`<h1 id="notely-ai-knowledge-retrieval-validation-report" tabindex="-1">Notely AI Knowledge Retrieval Validation Report <a class="header-anchor" href="#notely-ai-knowledge-retrieval-validation-report" aria-label="Permalink to &quot;Notely AI Knowledge Retrieval Validation Report&quot;">​</a></h1><p>Validation audit of Retrieval-Augmented Generation (RAG) pipeline in Notely. Analysis of embedding querying, knowledge graph traversal, tool registry, prompt construction, and UI observability.</p><hr><h2 id="findings-summary" tabindex="-1">Findings Summary <a class="header-anchor" href="#findings-summary" aria-label="Permalink to &quot;Findings Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Issue Title</th><th style="text-align:left;">Priority</th><th style="text-align:left;">Target Component / File</th><th style="text-align:left;">Complexity</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="#1-knowledge-graph-traversal-fails-silently-due-to-typo-bug">Knowledge Graph Traversal Fails Silently due to Typo Bug</a></td><td style="text-align:left;"><strong>Critical</strong></td><td style="text-align:left;">[ai/index.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/index.js)</td><td style="text-align:left;">Low</td></tr><tr><td style="text-align:left;"><a href="#2-current-note-content-blindness-in-ai-chat-and-streaming">Current Note Content Blindness in AI Chat and Streaming</a></td><td style="text-align:left;"><strong>Critical</strong></td><td style="text-align:left;">[src/hooks/useAIAssistant.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/src/hooks/useAIAssistant.js) / [ai/core/QueryExecutor.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/core/QueryExecutor.js)</td><td style="text-align:left;">Medium</td></tr><tr><td style="text-align:left;"><a href="#3-related-note-context-discarded-as-dead-code">Related Note Context Discarded as Dead Code</a></td><td style="text-align:left;"><strong>Critical</strong></td><td style="text-align:left;">[ai/context/ContextManager.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/ContextManager.js) / [ai/core/QueryExecutor.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/core/QueryExecutor.js)</td><td style="text-align:left;">Low</td></tr><tr><td style="text-align:left;"><a href="#4-broken-ui-source-references-observability">Broken UI Source References Observability</a></td><td style="text-align:left;"><strong>High</strong></td><td style="text-align:left;">[src/hooks/useAIAssistant.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/src/hooks/useAIAssistant.js) / [ai/core/QueryExecutor.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/core/QueryExecutor.js)</td><td style="text-align:left;">Low</td></tr><tr><td style="text-align:left;"><a href="#5-inefficient-in-memory-cosine-similarity-vector-search">Inefficient In-Memory Cosine Similarity Vector Search</a></td><td style="text-align:left;"><strong>High</strong></td><td style="text-align:left;">[ai/context/SemanticRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/SemanticRetriever.js)</td><td style="text-align:left;">High</td></tr><tr><td style="text-align:left;"><a href="#6-absence-of-unified-hybrid-retrieval-layer">Absence of Unified Hybrid Retrieval Layer</a></td><td style="text-align:left;"><strong>Medium</strong></td><td style="text-align:left;">[ai/core/QueryExecutor.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/core/QueryExecutor.js)</td><td style="text-align:left;">Medium</td></tr><tr><td style="text-align:left;"><a href="#7-no-semantic-chunk-deduplication-or-rank-tuning">No Semantic Chunk Deduplication or Rank Tuning</a></td><td style="text-align:left;"><strong>Medium</strong></td><td style="text-align:left;">[ai/context/SemanticRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/SemanticRetriever.js)</td><td style="text-align:left;">Low</td></tr><tr><td style="text-align:left;"><a href="#8-missing-performance-metrics-and-detailed-retrieval-logs">Missing Performance Metrics and Detailed Retrieval Logs</a></td><td style="text-align:left;"><strong>Medium</strong></td><td style="text-align:left;">[ai/context/SemanticRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/SemanticRetriever.js) / [ai/context/GraphRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/GraphRetriever.js)</td><td style="text-align:left;">Low</td></tr></tbody></table><hr><h2 id="detailed-findings" tabindex="-1">Detailed Findings <a class="header-anchor" href="#detailed-findings" aria-label="Permalink to &quot;Detailed Findings&quot;">​</a></h2><h3 id="_1-knowledge-graph-traversal-fails-silently-due-to-typo-bug" tabindex="-1">1. Knowledge Graph Traversal Fails Silently due to Typo Bug <a class="header-anchor" href="#_1-knowledge-graph-traversal-fails-silently-due-to-typo-bug" aria-label="Permalink to &quot;1. Knowledge Graph Traversal Fails Silently due to Typo Bug&quot;">​</a></h3><ul><li><strong>Priority</strong>: Critical</li><li><strong>Current Behaviour</strong>: In [ai/index.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/index.js#L115), [GraphRetriever](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/GraphRetriever.js) is instantiated with <code>aiAgent.graphDB ?? aiAgent.databaseManager</code>. On <code>aiAgent</code> ([ai/core/Agent.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/core/Agent.js)), these properties do not exist. The correct properties are <code>graphDb</code> (lowercase <code>b</code>) and <code>db</code> (database manager). Consequently, <code>graphRetriever</code> is instantiated with <code>undefined</code>. During execution, <code>exploreGraph</code> tool calls trigger <code>traverse()</code>, which crashes on <code>this.graphDB.db</code> lookup, gets caught by the internal <code>try-catch</code>, logs a misleading warning <code>Graph traversal failed (graph may not be built yet)</code>, and returns <code>[]</code>. No graph context is ever retrieved.</li><li><strong>Expected Behaviour</strong>: <code>GraphRetriever</code> must be constructed using <code>aiAgent.graphDb</code>. Traversal CTE query should successfully execute over the SQLite connection.</li><li><strong>Recommendation</strong>: Change instantiation in [ai/index.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/index.js) to:<div class="language-javascript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> graphRetriever</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> GraphRetriever</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(aiAgent.graphDb);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><strong>Estimated Complexity</strong>: Low (1 line fix)</li><li><strong>Dependencies</strong>: None</li></ul><h3 id="_2-current-note-content-blindness-in-ai-chat-and-streaming" tabindex="-1">2. Current Note Content Blindness in AI Chat and Streaming <a class="header-anchor" href="#_2-current-note-content-blindness-in-ai-chat-and-streaming" aria-label="Permalink to &quot;2. Current Note Content Blindness in AI Chat and Streaming&quot;">​</a></h3><ul><li><strong>Priority</strong>: Critical</li><li><strong>Current Behaviour</strong>: In [ai/core/QueryExecutor.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/core/QueryExecutor.js#L29), <code>ContextEngine.buildContext()</code> is invoked with <code>activeNoteContent: context.activeNoteContent || null</code>. However, in [useAIAssistant.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/src/hooks/useAIAssistant.js#L415) <code>aiQueryStream</code> does not extract or send the editor content in the payload context. For non-streaming chat requests, <code>Agent.query()</code> calls <code>ContextManager.buildQueryContext()</code>, which populates <code>fileContext</code> with only a 500-char preview <code>contentPreview</code> but omits the full <code>activeNoteContent</code> expected by <code>QueryExecutor</code>. As a result, the <code>if (activeNotePath &amp;&amp; activeNoteContent)</code> check in [ContextEngine.buildContext()](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/ContextEngine.js#L49) fails, and no note content is appended to the system prompt. The LLM is blind to note content during conversations.</li><li><strong>Expected Behaviour</strong>: The LLM must receive the full active note content (up to the character limit) in the system prompt.</li><li><strong>Recommendation</strong>: <ul><li>Update frontend [useAIAssistant.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/src/hooks/useAIAssistant.js) to include the active note&#39;s full text content in the IPC query payload as <code>activeNoteContent</code>.</li><li>Ensure the backend retrieves the full note contents from disk using <code>documentService.getDocumentContent(currentFile)</code> in <code>Agent.query</code> if not supplied by the frontend.</li></ul></li><li><strong>Estimated Complexity</strong>: Medium</li><li><strong>Dependencies</strong>: Typo bug fix in graph instantiation to ensure clean execution.</li></ul><h3 id="_3-related-note-context-discarded-as-dead-code" tabindex="-1">3. Related Note Context Discarded as Dead Code <a class="header-anchor" href="#_3-related-note-context-discarded-as-dead-code" aria-label="Permalink to &quot;3. Related Note Context Discarded as Dead Code&quot;">​</a></h3><ul><li><strong>Priority</strong>: Critical</li><li><strong>Current Behaviour</strong>: [ContextManager.buildQueryContext()](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/ContextManager.js#L137) performs keyword-based search over documents to populate <code>relatedDocuments</code> array. However, this array is completely ignored by <code>QueryExecutor._prepareConfig()</code>. Furthermore, <code>ContextManager.buildSystemPrompt()</code> is dead code (never called). As a result, related notes retrieved via keyword search are discarded and never exposed to the LLM prompt.</li><li><strong>Expected Behaviour</strong>: Relevant search results and keyword-matched related notes should be injected into the system prompt context or exposed as pre-fetched reference lists.</li><li><strong>Recommendation</strong>: Inject keyword-matched related documents into the combined workspace context inside <code>QueryExecutor.js</code>.</li><li><strong>Estimated Complexity</strong>: Low</li><li><strong>Dependencies</strong>: None</li></ul><h3 id="_4-broken-ui-source-references-observability" tabindex="-1">4. Broken UI Source References Observability <a class="header-anchor" href="#_4-broken-ui-source-references-observability" aria-label="Permalink to &quot;4. Broken UI Source References Observability&quot;">​</a></h3><ul><li><strong>Priority</strong>: High</li><li><strong>Current Behaviour</strong>: In [useAIAssistant.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/src/hooks/useAIAssistant.js#L451), the assistant bubble references list is populated using <code>finalResult?.references || []</code>. However, the backend <code>QueryExecutor</code> execution output returns a <code>trace</code> array of tool steps, but no <code>references</code> property. Additionally, for loaded conversation history in <code>loadConversation()</code>, the code maps <code>references: m.metadata?.trace?.flatMap(t =&gt; t.references || [])</code>. Since the trace objects stored in [MemoryDB](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/memory/MemoryDB.js) only contain <code>name</code>, <code>args</code>, and <code>output</code>, <code>t.references</code> is always undefined. Source citations are always empty in the UI.</li><li><strong>Expected Behaviour</strong>: The frontend should parse the <code>trace</code> output of the <code>searchNotes</code> tool calls to extract file paths and similarity scores, mapping them to the <code>references</code> UI state.</li><li><strong>Recommendation</strong>: Update [useAIAssistant.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/src/hooks/useAIAssistant.js) to derive references from trace:<div class="language-javascript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> references</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> finalResult?.trace</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ?.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t.name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;searchNotes&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Array.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">isArray</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t.output))</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ?.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flatMap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t.output.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ({ path: r.note_path, relevance: r.score }))) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">||</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [];</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div>And update conversation history loader to apply similar extraction logic on the saved trace metadata.</li><li><strong>Estimated Complexity</strong>: Low</li><li><strong>Dependencies</strong>: None</li></ul><h3 id="_5-inefficient-in-memory-cosine-similarity-vector-search" tabindex="-1">5. Inefficient In-Memory Cosine Similarity Vector Search <a class="header-anchor" href="#_5-inefficient-in-memory-cosine-similarity-vector-search" aria-label="Permalink to &quot;5. Inefficient In-Memory Cosine Similarity Vector Search&quot;">​</a></h3><ul><li><strong>Priority</strong>: High</li><li><strong>Current Behaviour</strong>: In [SemanticRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/SemanticRetriever.js#L40), every semantic search query reads all rows from the <code>chunks</code> table (including full binary embedding blobs) into JS memory: <code>SELECT id, note_path, embedding FROM chunks WHERE embedding IS NOT NULL</code> The similarity scoring is calculated in a synchronous JS <code>for</code> loop. This blocks the single-threaded Node.js event loop during searches on larger vaults.</li><li><strong>Expected Behaviour</strong>: Embedding databases should utilize indexed databases or fast vectorized query structures (like SQLite vector extensions or native SQLite math/ordering if possible, or batched chunk processing) to avoid pulling all vectors into memory.</li><li><strong>Recommendation</strong>: Introduce pagination or batch loading for vector rows. Calculate cosine similarity in smaller chunks of records, or explore lightweight vector libraries.</li><li><strong>Estimated Complexity</strong>: High</li><li><strong>Dependencies</strong>: None</li></ul><h3 id="_6-absence-of-unified-hybrid-retrieval-layer" tabindex="-1">6. Absence of Unified Hybrid Retrieval Layer <a class="header-anchor" href="#_6-absence-of-unified-hybrid-retrieval-layer" aria-label="Permalink to &quot;6. Absence of Unified Hybrid Retrieval Layer&quot;">​</a></h3><ul><li><strong>Priority</strong>: Medium</li><li><strong>Current Behaviour</strong>: Semantic search (<code>searchNotes</code>) and Knowledge Graph traversal (<code>exploreGraph</code>) are exposed to the LLM as separate, disconnected tools. The application does not perform automated hybrid retrieval. It relies on the LLM to decide which tool to call and sequentially integrate results.</li><li><strong>Expected Behaviour</strong>: The system should support a unified RAG strategy that automatically executes semantic search, traverses the graph for neighboring entities, merges the results using Reciprocal Rank Fusion (RRF), and feeds a highly ranked context directly into the prompt.</li><li><strong>Recommendation</strong>: Create a hybrid search orchestrator tool or pre-retrieval pipeline that automatically merges semantic results with graph relations to improve context quality and save LLM reasoning steps.</li><li><strong>Estimated Complexity</strong>: Medium</li><li><strong>Dependencies</strong>: Typo bug fix in graph database connection.</li></ul><h3 id="_7-no-semantic-chunk-deduplication-or-rank-tuning" tabindex="-1">7. No Semantic Chunk Deduplication or Rank Tuning <a class="header-anchor" href="#_7-no-semantic-chunk-deduplication-or-rank-tuning" aria-label="Permalink to &quot;7. No Semantic Chunk Deduplication or Rank Tuning&quot;">​</a></h3><ul><li><strong>Priority</strong>: Medium</li><li><strong>Current Behaviour</strong>: [SemanticRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/SemanticRetriever.js) does not deduplicate overlapping or identical chunks retrieved from the same note. The Top-K parameter (<code>topK</code>) is set as a default of 5, but there is no vault-wide threshold tuning or token budget constraint applied directly to the retrieval query.</li><li><strong>Expected Behaviour</strong>: If multiple retrieved chunks belong to the same note, they should be merged or adjacent chunks should be joined. Similarity score thresholds should filter out low-relevance results.</li><li><strong>Recommendation</strong>: Add a deduplication step post-sorting. Apply a similarity score cutoff threshold (e.g., <code>score &gt; 0.7</code>) to drop noisy matches.</li><li><strong>Estimated Complexity</strong>: Low</li><li><strong>Dependencies</strong>: None</li></ul><h3 id="_8-missing-performance-metrics-and-detailed-retrieval-logs" tabindex="-1">8. Missing Performance Metrics and Detailed Retrieval Logs <a class="header-anchor" href="#_8-missing-performance-metrics-and-detailed-retrieval-logs" aria-label="Permalink to &quot;8. Missing Performance Metrics and Detailed Retrieval Logs&quot;">​</a></h3><ul><li><strong>Priority</strong>: Medium</li><li><strong>Current Behaviour</strong>: Subsystem loggers do not log performance metrics for retrieval steps. No duration metrics are captured for: <ul><li>Vector generation latency</li><li>SQLite chunk reading and cosine search duration</li><li>Graph recursive CTE depth traversal duration</li></ul></li><li><strong>Expected Behaviour</strong>: Performance benchmarks and durations should be logged on every query event to enable diagnostics in the developer tool/inspector.</li><li><strong>Recommendation</strong>: Add high-resolution performance timers (<code>performance.now()</code>) inside [SemanticRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/SemanticRetriever.js) and [GraphRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/GraphRetriever.js), and log the durations.</li><li><strong>Estimated Complexity</strong>: Low</li><li><strong>Dependencies</strong>: None</li></ul><hr><h2 id="prioritized-implementation-checklist" tabindex="-1">Prioritized Implementation Checklist <a class="header-anchor" href="#prioritized-implementation-checklist" aria-label="Permalink to &quot;Prioritized Implementation Checklist&quot;">​</a></h2><h3 id="phase-1-critical-fixes-data-pipeline-corrections-urgent" tabindex="-1">Phase 1: Critical Fixes &amp; Data Pipeline Corrections (Urgent) <a class="header-anchor" href="#phase-1-critical-fixes-data-pipeline-corrections-urgent" aria-label="Permalink to &quot;Phase 1: Critical Fixes &amp; Data Pipeline Corrections (Urgent)&quot;">​</a></h3><ul><li>[ ] Fix typo in [ai/index.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/index.js) to resolve the <code>graphRetriever</code> initialization bug, enabling graph traversal.</li><li>[ ] Update [useAIAssistant.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/src/hooks/useAIAssistant.js) to transmit the full <code>activeNoteContent</code> in IPC query payload.</li><li>[ ] Fall back to disk read of note content in backend <code>Agent.query</code> when the frontend payload is missing the content.</li><li>[ ] Fix dead code in <code>QueryExecutor</code> to append related notes context and restore <code>ContextManager.buildQueryContext</code> relevance.</li></ul><h3 id="phase-2-observability-quality-improvements-high-priority" tabindex="-1">Phase 2: Observability &amp; Quality Improvements (High Priority) <a class="header-anchor" href="#phase-2-observability-quality-improvements-high-priority" aria-label="Permalink to &quot;Phase 2: Observability &amp; Quality Improvements (High Priority)&quot;">​</a></h3><ul><li>[ ] Implement trace-parsing logic in [useAIAssistant.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/src/hooks/useAIAssistant.js) to restore source citations in the chat bubble references.</li><li>[ ] Add post-retrieval semantic deduplication and minimum similarity score threshold in [SemanticRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/SemanticRetriever.js).</li><li>[ ] Add performance duration metrics and detailed event logs for vector search, graph walk, and prompt construction.</li></ul><h3 id="phase-3-performance-hybrid-search-optimization-medium-priority" tabindex="-1">Phase 3: Performance &amp; Hybrid Search Optimization (Medium Priority) <a class="header-anchor" href="#phase-3-performance-hybrid-search-optimization-medium-priority" aria-label="Permalink to &quot;Phase 3: Performance &amp; Hybrid Search Optimization (Medium Priority)&quot;">​</a></h3><ul><li>[ ] Optimize [SemanticRetriever.js](file:///c:/Users/oksbw/OneDrive/Desktop/Antigravity Workspace/Notely/ai/context/SemanticRetriever.js) vector search to avoid loading all vector blobs into memory simultaneously (implement batched parsing/calculations).</li><li>[ ] Design and implement a unified hybrid retrieval step merging semantic search and graph connections using Reciprocal Rank Fusion (RRF).</li></ul>`,31)])])}const u=t(a,[["render",o]]);export{g as __pageData,u as default};
